parameters.jsCode:
const body = $input.first().json.body;
if (!body) return [];

// Determinar el canal y recuperar la mensajería del payload
const object = body.object;
const entry = body.entry?.[0];
const messaging = entry?.messaging?.[0];

if (!messaging || !messaging.message) return [];

const sender_id = messaging.sender?.id;
const recipient_id = messaging.recipient?.id;
const text = messaging.message.text;

if (!sender_id || !text) return [];

// Prevenir auto-respuestas infinitas (Meta envía eventos tipo echo de la propia cuenta)
if (messaging.message.is_echo === true || sender_id === recipient_id) {
  return [];
}

const channel = object === 'instagram' ? 'instagram' : 'facebook';
const contact_name = channel === 'instagram' ? 'Cliente Instagram' : 'Cliente Facebook';

return [{
  json: {
    text: text,
    sender_id: sender_id,
    recipient_id: recipient_id,
    contact_name: contact_name,
    channel: channel
  }
}];

